const raw = $input.first().json.text;
let brief;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  brief = match ? JSON.parse(match[0]) : {};
} catch(e) {
  brief = { error: 'No se pudo parsear', raw: raw };
}
return [{ json: { brief, rawResponse: raw } }];

